import java.util.*;

public class Solution {
    public int[] maxSegSumAfterQueries(int[] nums, int[] removeQueries) {
        int n = nums.length;
        int[] answer = new int[n];
        TreeSet<Integer> removed = new TreeSet<>();
        removed.add(-1);
        removed.add(n);

        int currentSum = 0, maxSum = 0;
        for (int i = 0; i < n; ++i) {
            if (nums[i] > 0) currentSum += nums[i];
            else {
                maxSum = Math.max(maxSum, currentSum);
                currentSum = 0;
            }
        }
        maxSum = Math.max(maxSum, currentSum);

        for (int i = 0; i < n; ++i) {
            int removeIdx = removeQueries[i];
            answer[i] = maxSum;
            nums[removeIdx] = -nums[removeIdx];

            int leftIdx = removed.higher(removeIdx);
            int rightIdx = removed.lower(removeIdx);

            int leftSum = 0, rightSum = 0;
            for (int j = leftIdx - 1; j >= 0; --j) {
                if (nums[j] < 0) leftSum -= nums[j];
                else break;
            }
            for (int j = rightIdx + 1; j < n; ++j) {
                if (nums[j] < 0) rightSum -= nums[j];
                else break;
            }

            maxSum -= Math.max(0, leftSum - (-nums[removeIdx]));
            maxSum -= Math.max(0, rightSum - (-nums[removeIdx]));
            maxSum += Math.max(0, leftSum + rightSum - (-nums[removeIdx]));

            removed.add(removeIdx);
        }

        return answer;
    }
}
